            if (!hasFocus && !binding?.customerEditOrderPickupAddressEditText?.text.isNullOrBlank()) {
                binding?.customerEditOrderPickupAddressLayout?.error = null
            }
        }

        binding?.customerEditOrderDestinationAddressEditText?.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && !binding?.customerEditOrderDestinationAddressEditText?.text.isNullOrBlank()) {
                binding?.customerEditOrderDestinationAddressLayout?.error = null
            }
        }

        binding?.customerEditOrderDescriptionEditText?.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && !binding?.customerEditOrderDescriptionEditText?.text.isNullOrBlank()) {
                binding?.root?.findViewById<com.google.android.material.textfield.TextInputLayout>(
                    com.example.mobilefinalproject.R.id.customer_edit_order_description_layout
                )?.error = null
            }
        }

        binding?.customerEditOrderBudgetEditText?.setOnFocusChangeListener { _, hasFocus ->
            if (!hasFocus && !binding?.customerEditOrderBudgetEditText?.text.isNullOrBlank()) {
                binding?.root?.findViewById<com.google.android.material.textfield.TextInputLayout>(
                    com.example.mobilefinalproject.R.id.customer_edit_order_budget_layout
                )?.error = null
            }
        }
    }

    private fun setupButtonListeners(orderId: Int) {
        binding?.customerEditOrderSubmitButton?.setOnClickListener {
            if (validateForm()) {
                submitOrder(orderId)
            }
        }

        binding?.customerEditOrderCancelButton?.setOnClickListener {
            findNavController().popBackStack()
        }
    }

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        } else {
            Log.e("EditOrder", "Gallery permission denied")
        }
    }

    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            binding?.customerEditOrderImagePreview?.let { imageView ->
                Picasso.get().load(selectedImageUri).into(imageView)
            }
            binding?.customerEditOrderImagePreview?.visibility = View.VISIBLE
            Log.d("EditOrder", "Image selected: $it")
        }
    }

    private val pickupAddressLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        when (result.resultCode) {
            AutocompleteActivity.RESULT_OK -> {
                val place = Autocomplete.getPlaceFromIntent(result.data ?: return@registerForActivityResult)
                val address = place.address ?: ""
                val lat = place.latLng?.latitude ?: 0.0
                val lng = place.latLng?.longitude ?: 0.0
                updatePickupLocation(address, lat, lng)
            }
            AutocompleteActivity.RESULT_ERROR -> {
                val status = Autocomplete.getStatusFromIntent(result.data ?: return@registerForActivityResult)
                Log.e("Places", status.statusMessage ?: "Unknown error")
            }
        }
    }

    private val destinationAddressLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        when (result.resultCode) {
            AutocompleteActivity.RESULT_OK -> {
                val place = Autocomplete.getPlaceFromIntent(result.data ?: return@registerForActivityResult)
                val address = place.address ?: ""
                val lat = place.latLng?.latitude ?: 0.0
                val lng = place.latLng?.longitude ?: 0.0
                updateDestinationLocation(address, lat, lng)
            }
            AutocompleteActivity.RESULT_ERROR -> {
                val status = Autocomplete.getStatusFromIntent(result.data ?: return@registerForActivityResult)
                Log.e("Places", status.statusMessage ?: "Unknown error")
            }
        }
    }

    private fun setupLocationPickers() {
        binding?.customerEditOrderPickupAddressEditText?.setOnClickListener {
            if (isPlacesAutocompleteEnabled) {
                val fields = listOf(Place.Field.ID, Place.Field.NAME, Place.Field.ADDRESS, Place.Field.LAT_LNG)
                val intent = Autocomplete.IntentBuilder(AutocompleteActivityMode.FULLSCREEN, fields).build(requireContext())
                pickupAddressLauncher.launch(intent)
            }
        }

        binding?.customerEditOrderDestinationAddressEditText?.setOnClickListener {
            if (isPlacesAutocompleteEnabled) {
                val fields = listOf(Place.Field.ID, Place.Field.NAME, Place.Field.ADDRESS, Place.Field.LAT_LNG)
                val intent = Autocomplete.IntentBuilder(AutocompleteActivityMode.FULLSCREEN, fields).build(requireContext())
                destinationAddressLauncher.launch(intent)
            }
        }
    }

    private fun setupDateTimePickers() {
        binding?.customerEditOrderPickupDateEditText?.setOnClickListener { showDatePicker() }
        binding?.customerEditOrderPickupTimeEditText?.setOnClickListener { time ->
            showTimePicker { binding?.customerEditOrderPickupTimeEditText?.setText(it) }
        }
    }

    private fun setupImagePicker() {
        binding?.customerEditOrderAddImageButton?.setOnClickListener {
            checkAndRequestGalleryPermission()
        }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
            android.Manifest.permission.READ_MEDIA_IMAGES
        } else {
            android.Manifest.permission.READ_EXTERNAL_STORAGE
        }
        when {
            ContextCompat.checkSelfPermission(requireContext(), permission) == PackageManager.PERMISSION_GRANTED ->
                imagePickerLauncher.launch(PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly))
            else -> permissionLauncher.launch(permission)
        }
    }

    private fun showDatePicker() {
        DatePickerDialog(
            requireContext(),
            { _, year, month, dayOfMonth ->
                val selectedDate = Calendar.getInstance()
                selectedDate.set(year, month, dayOfMonth)
                val dateFormat = SimpleDateFormat("dd/MM/yyyy", Locale.getDefault())
                binding?.customerEditOrderPickupDateEditText?.setText(dateFormat.format(selectedDate.time))
            },
            calendar.get(Calendar.YEAR),
            calendar.get(Calendar.MONTH),
            calendar.get(Calendar.DAY_OF_MONTH)
        ).show()
    }

    private fun showTimePicker(callback: (String) -> Unit) {
        TimePickerDialog(
            requireContext(),
            { _, hourOfDay, minute ->
                callback(String.format(Locale.getDefault(), "%02d:%02d", hourOfDay, minute))
            },
            calendar.get(Calendar.HOUR_OF_DAY),
            calendar.get(Calendar.MINUTE),
            true
        ).show()
    }

    private fun validateForm(): Boolean {
        var isValid = true

        val pickupText = binding?.customerEditOrderPickupAddressEditText?.text?.toString()?.trim().orEmpty()
        val destinationText = binding?.customerEditOrderDestinationAddressEditText?.text?.toString()?.trim().orEmpty()

        if (pickupAddress.isBlank() && pickupText.isBlank()) {
            binding?.customerEditOrderPickupAddressLayout?.error = "Pickup address is required"
            isValid = false
        } else {
            binding?.customerEditOrderPickupAddressLayout?.error = null
        }

        if (dropoffAddress.isBlank() && destinationText.isBlank()) {
            binding?.customerEditOrderDestinationAddressLayout?.error = "Destination address is required"
            isValid = false
        } else {
            binding?.customerEditOrderDestinationAddressLayout?.error = null
        }

        val budgetText = binding?.customerEditOrderBudgetEditText?.text?.toString()?.trim()
        val budgetLayout = binding?.root?.findViewById<com.google.android.material.textfield.TextInputLayout>(
            com.example.mobilefinalproject.R.id.customer_edit_order_budget_layout
        )
        if (budgetText.isNullOrEmpty()) {
            budgetLayout?.error = "Budget is required"
            isValid = false
        } else {
            val budget = budgetText.toDoubleOrNull()
            if (budget == null || budget <= 0) {
                budgetLayout?.error = "Budget must be a valid positive amount"
                isValid = false
            } else {
                budgetLayout?.error = null
            }
        }

        return isValid
    }

    private fun submitOrder(orderId: Int) {
        val finalPickupAddress = binding?.customerEditOrderPickupAddressEditText?.text?.toString()?.trim()
            ?.takeIf { it.isNotBlank() } ?: pickupAddress
        val finalDropoffAddress = binding?.customerEditOrderDestinationAddressEditText?.text?.toString()?.trim()
            ?.takeIf { it.isNotBlank() } ?: dropoffAddress

        if (finalPickupAddress.isBlank() || finalDropoffAddress.isBlank()) return

        val budgetDollars = binding?.customerEditOrderBudgetEditText?.text?.toString()?.trim()?.toDoubleOrNull() ?: return
        val priceCents = (budgetDollars * 100).toInt()
        val description = binding?.customerEditOrderDescriptionEditText?.text?.toString()?.trim()

        orderViewModel.updateOrder(
            orderId,
            OrderUpdateRequest(
                pickupAddress = finalPickupAddress,
                pickupLat = pickupLat.takeIf { it != 0.0 },
                pickupLng = pickupLng.takeIf { it != 0.0 },
                dropoffAddress = finalDropoffAddress,
                dropoffLat = dropoffLat.takeIf { it != 0.0 },
                dropoffLng = dropoffLng.takeIf { it != 0.0 },
                cargoDescription = description,
                priceCents = priceCents
            ),
            onSuccess = {
                Toast.makeText(requireContext(), "Order updated successfully", Toast.LENGTH_SHORT).show()
                findNavController().popBackStack()
            }
        )
    }

    private fun updatePickupLocation(address: String, latitude: Double, longitude: Double) {
        pickupAddress = address; pickupLat = latitude; pickupLng = longitude
        binding?.customerEditOrderPickupAddressEditText?.setText(address)
        binding?.customerEditOrderPickupAddressLayout?.error = null
    }

    private fun updateDestinationLocation(address: String, latitude: Double, longitude: Double) {
        dropoffAddress = address; dropoffLat = latitude; dropoffLng = longitude
        binding?.customerEditOrderDestinationAddressEditText?.setText(address)
        binding?.customerEditOrderDestinationAddressLayout?.error = null
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.customer

import android.net.Uri
import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.activity.result.contract.ActivityResultContracts
import androidx.activity.result.PickVisualMediaRequest
import androidx.core.content.ContextCompat
import android.content.pm.PackageManager
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.databinding.FragmentCustomerEditProfileBinding
import com.example.mobilefinalproject.session.UserSessionManager
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.squareup.picasso.Picasso

class CustomerEditProfileFragment : Fragment() {

    private val customerViewModel: CustomerViewModel by activityViewModels()
    private var binding: FragmentCustomerEditProfileBinding? = null
    private var selectedImageUri: Uri? = null

    // Image picker launcher
    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            binding?.customerEditProfileImageView?.let { imageView ->
                Picasso.get()
                    .load(selectedImageUri)
                    .into(imageView)
            }
        }
    }

    // Permission request launcher
    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerEditProfileBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        // Observe customer data and populate fields
        customerViewModel.customer.observe(viewLifecycleOwner) { customer ->
            if (customer != null) {
                binding?.customerEditProfileFullNameEditText?.setText(customer.fullName)
                binding?.customerEditProfileIdEditText?.setText(customer.id)
            }
        }

        // Setup button click listeners
        binding?.customerEditProfileSaveButton?.setOnClickListener {
            saveProfile()
        }

        binding?.customerEditProfileCancelButton?.setOnClickListener {
            findNavController().navigateUp()
        }

        binding?.customerEditProfileChangePictureButton?.setOnClickListener {
            checkAndRequestGalleryPermission()
        }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission =
            android.Manifest.permission.READ_MEDIA_IMAGES

        when {
            ContextCompat.checkSelfPermission(
                requireContext(),
                permission
            ) == PackageManager.PERMISSION_GRANTED -> {
                imagePickerLauncher.launch(
                    PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
                )
            }
            else -> {
                permissionLauncher.launch(permission)
            }
        }
    }

    private fun saveProfile() {
        val binding = binding ?: return
        val updatedFullName = binding.customerEditProfileFullNameEditText.text.toString().trim()

        if (updatedFullName.isEmpty()) {
            binding.customerEditProfileFullNameEditText.error = "Full name cannot be empty"
            return
        }

        // Get current customer from ViewModel
        val currentCustomer = customerViewModel.customer.value
        if (currentCustomer != null) {
            val updatedCustomer = currentCustomer.copy(fullName = updatedFullName)
            customerViewModel.updateCustomer(updatedCustomer)
            UserSessionManager.saveCustomer(requireContext(), updatedCustomer)
            findNavController().navigateUp()
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.customer

import android.net.Uri
import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.activity.result.contract.ActivityResultContracts
import androidx.activity.result.PickVisualMediaRequest
import androidx.core.content.ContextCompat
import android.content.pm.PackageManager
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.databinding.FragmentCustomerEditProfileBinding
import com.example.mobilefinalproject.viewmodels.CustomerViewModel
import com.squareup.picasso.Picasso

class CustomerEditProfileFragment : Fragment() {

    private val customerViewModel: CustomerViewModel by activityViewModels()
    private var binding: FragmentCustomerEditProfileBinding? = null
    private var selectedImageUri: Uri? = null

    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            binding?.customerEditProfileImageView?.let { imageView ->
                Picasso.get().load(selectedImageUri).into(imageView)
            }
        }
    }

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerEditProfileBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        customerViewModel.userMe.observe(viewLifecycleOwner) { user ->
            if (user != null) {
                binding?.customerEditProfileFullNameEditText?.setText(user.fullName)
                binding?.customerEditProfileIdEditText?.setText(user.id.toString())
            }
        }

        binding?.customerEditProfileSaveButton?.setOnClickListener { saveProfile() }
        binding?.customerEditProfileCancelButton?.setOnClickListener { findNavController().navigateUp() }
        binding?.customerEditProfileChangePictureButton?.setOnClickListener { checkAndRequestGalleryPermission() }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission = android.Manifest.permission.READ_MEDIA_IMAGES
        when {
            ContextCompat.checkSelfPermission(requireContext(), permission) == PackageManager.PERMISSION_GRANTED ->
                imagePickerLauncher.launch(PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly))
            else -> permissionLauncher.launch(permission)
        }
    }

    private fun saveProfile() {
        val binding = binding ?: return
        val updatedFullName = binding.customerEditProfileFullNameEditText.text.toString().trim()

        if (updatedFullName.isEmpty()) {
            binding.customerEditProfileFullNameEditText.error = "Full name cannot be empty"
            return
        }

        customerViewModel.updateProfile(fullName = updatedFullName, onSuccess = {
            findNavController().navigateUp()
        })
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.customer

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.ArrayAdapter
import androidx.fragment.app.Fragment
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.adapters.CustomerDeliveryAdapter
import com.example.mobilefinalproject.databinding.FragmentCustomerMyOrdersBinding
import com.example.mobilefinalproject.network.dto.OrderRead
import com.example.mobilefinalproject.viewmodels.OrderViewModel

class CustomerMyOrdersFragment : Fragment() {

    private val orderViewModel: OrderViewModel by activityViewModels()
    private var binding: FragmentCustomerMyOrdersBinding? = null
    private var adapter: CustomerDeliveryAdapter? = null
    private var allOrders: List<OrderRead> = emptyList()
    private var selectedStatusFilter: String = ALL_STATUS_FILTER

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentCustomerMyOrdersBinding.inflate(inflater, container, false)
        setupRecyclerView()
        setupStatusFilter()
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)
        orderViewModel.loadMyOrders()
    }

    override fun onResume() {
        super.onResume()
        orderViewModel.loadMyOrders()
    }

    private fun setupRecyclerView() {
        binding?.customerMyOrdersRecyclerView?.layoutManager = LinearLayoutManager(context)
        binding?.customerMyOrdersRecyclerView?.setHasFixedSize(true)

        adapter = CustomerDeliveryAdapter(
            onCancel = { order ->
                orderViewModel.cancelOrder(order.id)
            },
            onEdit = { order ->
                val action = CustomerMyOrdersFragmentDirections
                    .actionCustomerMyOrdersFragmentToCustomerEditOrderFragment(order.id)
                findNavController().navigate(action)
            },
            onDetails = { order ->
                com.example.mobilefinalproject.ui.dialogs.DeliveryDetailsDialog(requireContext()).show(
                    order = order,
                    showActions = false,
                    showDriverInfo = true
                )
            }
        )
        binding?.customerMyOrdersRecyclerView?.adapter = adapter

        orderViewModel.customerOrders.observe(viewLifecycleOwner) { orders ->
            allOrders = orders
            applyFilter()
        }
    }

    private fun setupStatusFilter() {
        val spinnerAdapter = ArrayAdapter.createFromResource(
            requireContext(),
            R.array.customer_order_status_filter_options,
            android.R.layout.simple_spinner_item
        ).also { it.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item) }

        binding?.customerMyOrdersStatusSpinner?.adapter = spinnerAdapter
        binding?.customerMyOrdersStatusSpinner?.setSelection(0, false)
        binding?.customerMyOrdersStatusSpinner?.onItemSelectedListener =
            object : android.widget.AdapterView.OnItemSelectedListener {
                override fun onItemSelected(parent: android.widget.AdapterView<*>, view: View?, pos: Int, id: Long) {
                    selectedStatusFilter = parent.getItemAtPosition(pos)?.toString().orEmpty()
                    applyFilter()
                }
                override fun onNothingSelected(parent: android.widget.AdapterView<*>) {
                    selectedStatusFilter = ALL_STATUS_FILTER
                    applyFilter()
                }
            }
    }

    private fun applyFilter() {
        val filtered = when (selectedStatusFilter) {
            STATUS_PENDING     -> allOrders.filter { it.status == "pending" }
            STATUS_ACCEPTED    -> allOrders.filter { it.status == "accepted" }
            STATUS_IN_PROGRESS -> allOrders.filter { it.status == "in_progress" }
            STATUS_COMPLETED   -> allOrders.filter { it.status == "completed" }
            STATUS_CANCELLED   -> allOrders.filter { it.status == "cancelled" }
            else -> allOrders
        }
        adapter?.submitList(filtered)
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }

    companion object {
        private const val ALL_STATUS_FILTER = "All"
        private const val STATUS_PENDING     = "Pending"
        private const val STATUS_ACCEPTED    = "Accepted"
        private const val STATUS_IN_PROGRESS = "In Progress"
        private const val STATUS_COMPLETED   = "Completed"
        private const val STATUS_CANCELLED   = "Cancelled"
    }
}

