package com.example.mobilefinalproject.ui.driver

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.activityViewModels
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.mobilefinalproject.adapters.ActiveDeliveryAdapter
import com.example.mobilefinalproject.databinding.FragmentDriverActiveDeliveriesBinding
import com.example.mobilefinalproject.viewmodels.OrderViewModel

class DriverActiveDeliveriesFragment : Fragment() {
    private val orderViewModel: OrderViewModel by activityViewModels()
    private var binding: FragmentDriverActiveDeliveriesBinding? = null

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverActiveDeliveriesBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        binding?.driverActiveDeliveriesRecyclerView?.layoutManager = LinearLayoutManager(requireContext())

        orderViewModel.activeOrders.observe(viewLifecycleOwner) { orders ->
            binding?.driverActiveDeliveriesRecyclerView?.adapter = ActiveDeliveryAdapter(
                orders,
                onStart = { order -> orderViewModel.startOrder(order.id) },
                onComplete = { order -> orderViewModel.completeOrder(order.id) }
            )
        }
    }

    override fun onResume() {
        super.onResume()
        orderViewModel.loadActiveDriverOrders()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.driver

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.activityViewModels
import androidx.recyclerview.widget.LinearLayoutManager
import com.example.mobilefinalproject.adapters.ActiveDeliveryAdapter
import com.example.mobilefinalproject.databinding.FragmentDriverActiveDeliveriesBinding
import com.example.mobilefinalproject.viewmodels.OrderViewModel

class DriverActiveDeliveriesFragment : Fragment() {
    private val orderViewModel: OrderViewModel by activityViewModels()
    private var binding: FragmentDriverActiveDeliveriesBinding? = null

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverActiveDeliveriesBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        binding?.driverActiveDeliveriesRecyclerView?.layoutManager = LinearLayoutManager(requireContext())

        orderViewModel.activeOrders.observe(viewLifecycleOwner) { orders ->
            binding?.driverActiveDeliveriesRecyclerView?.adapter = ActiveDeliveryAdapter(
                orders,
                onStart = { order -> orderViewModel.startOrder(order.id) },
                onComplete = { order -> orderViewModel.completeOrder(order.id) },
                onDetails = { order ->
                    com.example.mobilefinalproject.ui.dialogs.DeliveryDetailsDialog(requireContext()).show(
                        order = order,
                        showActions = false,
                        showDriverInfo = false
                    )
                },
                onCancel = { order -> orderViewModel.cancelOrder(order.id) }
            )
        }
    }

    override fun onResume() {
        super.onResume()
        orderViewModel.loadActiveDriverOrders()
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.driver

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.lifecycle.ViewModelProvider
import androidx.navigation.fragment.NavHostFragment
import androidx.navigation.ui.setupWithNavController
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.databinding.FragmentDriverContainerBinding
import com.example.mobilefinalproject.models.driver.Driver
import com.example.mobilefinalproject.session.UserSessionManager
import com.example.mobilefinalproject.viewmodels.DriverViewModel

class DriverContainerFragment : Fragment() {

    private var binding: FragmentDriverContainerBinding? = null

    private lateinit var driverViewModel: DriverViewModel

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverContainerBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        // Initialize ViewModel at activity scope
        driverViewModel = ViewModelProvider(requireActivity())[DriverViewModel::class.java]

        val driver = driverViewModel.driver.value
            ?: UserSessionManager.restoreDriver(requireContext())
            ?: Driver("123456789", "John Driver")

        if (driverViewModel.driver.value == null) {
            driverViewModel.setDriver(driver)
        }
        if (!UserSessionManager.hasSession(requireContext())) {
            UserSessionManager.saveDriver(requireContext(), driver)
        }

        // Get NavController from nested NavHostFragment
        val navHostFragment = binding?.let {
            childFragmentManager.findFragmentById(it.driverNavHostFragment.id) as NavHostFragment
        } ?: return
        val navController = navHostFragment.navController

        // Setup automatic navigation using driver_nav_graph
        binding?.driverBottomNavigation?.setupWithNavController(navController)

        // Hide bottom navigation on edit profile screen
        navController.addOnDestinationChangedListener { _, destination, _ ->
            when (destination.id) {
                R.id.driverEditProfileFragment -> {
                    binding?.driverBottomNavigation?.visibility = View.GONE
                }
                else -> {
                    binding?.driverBottomNavigation?.visibility = View.VISIBLE
                }
            }
        }
    }
}

package com.example.mobilefinalproject.ui.driver

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.lifecycle.ViewModelProvider
import androidx.navigation.fragment.NavHostFragment
import androidx.navigation.ui.setupWithNavController
