class DriverContainerFragment : Fragment() {

    private var binding: FragmentDriverContainerBinding? = null
    private lateinit var driverViewModel: DriverViewModel

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverContainerBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        // Initialize ViewModel at activity scope
        driverViewModel = ViewModelProvider(requireActivity())[DriverViewModel::class.java]

        // Load driver profile if not already loaded
        if (driverViewModel.userMe.value == null) {
            driverViewModel.loadMe()
        }

        // Mark driver as available (only if not currently busy with an order)
        driverViewModel.setAvailableIfNotBusy()

        // Get NavController from nested NavHostFragment
        val navHostFragment = binding?.let {
            childFragmentManager.findFragmentById(it.driverNavHostFragment.id) as NavHostFragment
        } ?: return
        val navController = navHostFragment.navController

        // Setup automatic navigation using driver_nav_graph
        binding?.driverBottomNavigation?.setupWithNavController(navController)

        // Hide bottom navigation on edit profile screen
        navController.addOnDestinationChangedListener { _, destination, _ ->
            when (destination.id) {
                R.id.driverEditProfileFragment -> {
                    binding?.driverBottomNavigation?.visibility = View.GONE
                }
                else -> {
                    binding?.driverBottomNavigation?.visibility = View.VISIBLE
                }
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

package com.example.mobilefinalproject.ui.driver

import android.content.pm.PackageManager
import android.net.Uri
import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.activity.result.PickVisualMediaRequest
import androidx.activity.result.contract.ActivityResultContracts
import androidx.core.content.ContextCompat
import androidx.fragment.app.Fragment
import androidx.fragment.app.activityViewModels
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.databinding.FragmentDriverEditProfileBinding
import com.example.mobilefinalproject.session.UserSessionManager
import com.example.mobilefinalproject.viewmodels.DriverViewModel
import com.squareup.picasso.Picasso

class DriverEditProfileFragment : Fragment() {
    private val driverViewModel: DriverViewModel by activityViewModels()
    private var binding: FragmentDriverEditProfileBinding? = null
    private var selectedImageUri: Uri? = null

    private val imagePickerLauncher = registerForActivityResult(
        ActivityResultContracts.PickVisualMedia()
    ) { uri ->
        uri?.let {
            selectedImageUri = it
            binding?.driverEditProfileImageView?.let { imageView ->
                Picasso.get().load(selectedImageUri).into(imageView)
            }
        }
    }

    private val permissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            imagePickerLauncher.launch(
                PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
            )
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverEditProfileBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        driverViewModel.driver.observe(viewLifecycleOwner) { driver ->
            if (driver != null) {
                binding?.driverEditProfileFullNameEditText?.setText(driver.fullName)
                binding?.driverEditProfileIdEditText?.setText(driver.id)
            }
        }

        binding?.driverEditProfileSaveButton?.setOnClickListener { saveProfile() }
        binding?.driverEditProfileCancelButton?.setOnClickListener { findNavController().navigateUp() }
        binding?.driverEditProfileChangePictureButton?.setOnClickListener { checkAndRequestGalleryPermission() }
    }

    private fun checkAndRequestGalleryPermission() {
        val permission = android.Manifest.permission.READ_MEDIA_IMAGES

        when {
            ContextCompat.checkSelfPermission(requireContext(), permission) == PackageManager.PERMISSION_GRANTED -> {
                imagePickerLauncher.launch(
                    PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly)
                )
            }
            else -> permissionLauncher.launch(permission)
        }
    }

    private fun saveProfile() {
        val currentBinding = binding ?: return
        val updatedFullName = currentBinding.driverEditProfileFullNameEditText.text.toString().trim()

        if (updatedFullName.isEmpty()) {
            currentBinding.driverEditProfileFullNameEditText.error = "Full name cannot be empty"
            return
        }

        val currentDriver = driverViewModel.driver.value ?: return
        val updatedDriver = currentDriver.copy(fullName = updatedFullName)
        driverViewModel.updateDriver(updatedDriver)
        UserSessionManager.saveDriver(requireContext(), updatedDriver)
        findNavController().navigateUp()
    }
}

