package com.example.mobilefinalproject.ui.driver

import com.example.mobilefinalproject.models.Delivery

object DriverFinderMapClusterer {

    data class DeliveryMapPoint(
        val latitude: Double,
        val longitude: Double,
        val delivery: Delivery,
        val markerType: MarkerType,
        val title: String,
        val snippet: String,
    )

    data class Cluster(
        val points: List<DeliveryMapPoint>,
        val centerLatitude: Double,
        val centerLongitude: Double,
    ) {
        val isSinglePoint: Boolean = points.size == 1
    }

    enum class MarkerType {
        PICKUP,
        DROPOFF,
    }

    fun toMapPoints(deliveries: List<Delivery>): List<DeliveryMapPoint> = buildList {
        deliveries.forEach { delivery ->
            if (delivery.pickupLat != 0.0 || delivery.pickupLng != 0.0) {
                add(
                    DeliveryMapPoint(
                        latitude = delivery.pickupLat,
                        longitude = delivery.pickupLng,
                        delivery = delivery,
                        markerType = MarkerType.PICKUP,
                        title = "Pickup - ${delivery.customerName}",
                        snippet = delivery.pickupAddress,
                    )
                )
            }

            if (delivery.dropoffLat != 0.0 || delivery.dropoffLng != 0.0) {
                add(
                    DeliveryMapPoint(
                        latitude = delivery.dropoffLat,
                        longitude = delivery.dropoffLng,
                        delivery = delivery,
                        markerType = MarkerType.DROPOFF,
                        title = "Drop-off - ${delivery.customerName}",
                        snippet = delivery.dropoffAddress,
                    )
                )
            }
        }
    }

    fun cluster(points: List<DeliveryMapPoint>, zoom: Double): List<Cluster> {
        if (points.isEmpty()) {
            return emptyList()
        }

        val cellSizeDegrees = cellSizeDegrees(zoom)
        return points
            .groupBy { point ->
                val latBucket = (point.latitude / cellSizeDegrees).toInt()
                val lonBucket = (point.longitude / cellSizeDegrees).toInt()
                "$latBucket:$lonBucket"
            }
            .values
            .map { clusteredPoints ->
                Cluster(
                    points = clusteredPoints,
                    centerLatitude = clusteredPoints.map { it.latitude }.average(),
                    centerLongitude = clusteredPoints.map { it.longitude }.average(),
                )
            }
    }

    fun cellSizeDegrees(zoom: Double): Double = when {
        zoom < 10.0 -> 0.05
        zoom < 12.0 -> 0.02
        zoom < 14.0 -> 0.01
        zoom < 16.0 -> 0.005
        else -> 0.002
    }

    fun nextClusterZoom(currentZoom: Double): Double = (currentZoom + 1.0).coerceAtMost(20.0)
}

package com.example.mobilefinalproject.ui.driver

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.activityViewModels
import androidx.navigation.Navigation
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.databinding.FragmentDriverProfileBinding
import com.example.mobilefinalproject.models.driver.Driver
import com.example.mobilefinalproject.session.UserSessionManager
import com.example.mobilefinalproject.viewmodels.DriverViewModel

class DriverProfileFragment : Fragment() {
    private val driverViewModel: DriverViewModel by activityViewModels()
    private var driver: Driver? = null
    private var binding: FragmentDriverProfileBinding? = null

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverProfileBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        driverViewModel.driver.observe(viewLifecycleOwner) { driver ->
            this.driver = driver
            updateUI()
        }

        // Setup edit profile button click listener
        binding?.driverProfileEditButton?.setOnClickListener {
            findNavController().navigate(R.id.action_driverProfileFragment_to_driverEditProfileFragment)
        }

        // Setup logout button click listener
        binding?.driverProfileLogoutButton?.setOnClickListener {
            logout()
        }
    }

    private fun updateUI() {
        binding?.driverProfileNameTextView?.text = this.driver?.fullName
        binding?.driverProfileIdTextView?.text = this.driver?.id
    }

    private fun logout() {
        driverViewModel.clearDriver()
        UserSessionManager.clearSession(requireContext())
        val parentNavController = Navigation.findNavController(requireActivity(), R.id.nav_host_fragment)
        parentNavController.navigate(R.id.action_global_loginFragment)
    }
}

package com.example.mobilefinalproject.ui.driver

import android.os.Bundle
import androidx.fragment.app.Fragment
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.activityViewModels
import androidx.navigation.Navigation
import androidx.navigation.fragment.findNavController
import com.example.mobilefinalproject.R
import com.example.mobilefinalproject.databinding.FragmentDriverProfileBinding
import com.example.mobilefinalproject.session.UserSessionManager
import com.example.mobilefinalproject.viewmodels.DriverViewModel

class DriverProfileFragment : Fragment() {
    private val driverViewModel: DriverViewModel by activityViewModels()
    private var binding: FragmentDriverProfileBinding? = null

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        binding = FragmentDriverProfileBinding.inflate(inflater, container, false)
        return binding?.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        driverViewModel.userMe.observe(viewLifecycleOwner) { user ->
            binding?.driverProfileNameTextView?.text = user?.fullName
            binding?.driverProfileIdTextView?.text = user?.id?.toString()
        }

        binding?.driverProfileEditButton?.setOnClickListener {
            findNavController().navigate(R.id.action_driverProfileFragment_to_driverEditProfileFragment)
        }

        binding?.driverProfileLogoutButton?.setOnClickListener {
            logout()
        }
    }

    private fun logout() {
        // Set driver offline on the backend first, then clear session and navigate
        driverViewModel.setOfflineAndLogout {
            driverViewModel.clearDriver()
            UserSessionManager.clearSession(requireContext())
            val parentNavController = Navigation.findNavController(requireActivity(), R.id.nav_host_fragment)
            parentNavController.navigate(R.id.action_global_loginFragment)
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        binding = null
    }
}

